1	var DBConfig = require('../config/db.config')()
2	var Sequelize = require('sequelize');
3	var db = {};
4	
5	initialize();
6	async function initialize() {
7	    // connect to db
8	    let sq_config = {
9	        dialect: 'postgres',
10	        host: DBConfig.HOST,
11	        schema: process.env.SCHEMA,
12	        logging: false,
13	        pool: {
14	            max: 22,
15	            min: 1,
16	            acquire: 600000,
17	            idle: 100000,
18	        },
19	        createdAt: false,
20	        updatedAt: false,
21	        timestamp: false,
22	        dialectOptions: {
23	            connectTimeout: 3000000,
24	        }
25	    };
26	
27	    const sequelize = new Sequelize(DBConfig.DB, DBConfig.DBUser, DBConfig.PASSWORD, sq_config);
28	
29	    // Populate the exported `db` object SYNCHRONOUSLY (before any await). Model
30	    // definitions don't need an authenticated connection, and index.js calls
31	    // startServer() -> db.LicenseFeedBacks.findAll() synchronously right after
32	    // require('./models/db') returns. Mutate (Object.assign) rather than
33	    // reassign so the `module.exports = db` reference stays valid. Awaiting
34	    // before this line would leave consumers holding an empty object.
35	    Object.assign(db, require('./db/init-models')(sequelize))
36	    db.sequelize = sequelize
37	
38	    try {
39	        await sequelize.authenticate();
40	    } catch (error) {
41	        console.error('Unable to connect to the database:', error);
42	        throw 'Unable to connect to the database:', error
43	    }
44	
45	    // Models are the schema source of truth: sync() creates brand-new tables
46	    // (e.g. the sample-tracking tables) without altering existing ones.
47	    await sequelize.sync();
48	
49	    // Idempotent, awaited migration block for FUTURE column additions. Runs
50	    // AFTER sync() so it never races. Use snake_case identifiers only (mixed
51	    // case folds to lowercase in unquoted Postgres DDL and orphans the column).
52	    await applySampleMigrations(sequelize);
53	}
54	
55	/**
56	 * Additive, idempotent DDL for the sample-tracking module. Every statement is
57	 * IF NOT EXISTS and individually guarded so a re-deploy never crashes boot.
58	 */
59	async function applySampleMigrations(sequelize) {
60	    const schema = process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
61	    const statements = [
62	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS sample_name VARCHAR(255)`,
63	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS quantity INTEGER`,
64	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS retail_price DECIMAL(12, 2)`,
65	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS fob_cost DECIMAL(12, 2)`,
66	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS customer_id_fk INTEGER`,
67	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS courier VARCHAR(20)`,
68	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS tracking_number VARCHAR(255)`,
69	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS factory_id_fk INTEGER`,
70	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS factory_group_id_fk INTEGER`,
71	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS box_id_fk INTEGER`,
72	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS office_location VARCHAR(20)`,
73	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS next_stop VARCHAR(50)`,
74	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS final_destination VARCHAR(50)`,
75	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS notes TEXT`,
76	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS item_id_fk INTEGER`,
77	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS prod_order_no_fk VARCHAR(255)`,
78	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_createdTime" VARCHAR(255)`,
79	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_createdUser" VARCHAR(255)`,
80	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_modTime" VARCHAR(255)`,
81	        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_modUser" VARCHAR(255)`,
82	        `ALTER TABLE ${schema}"sample_box" ADD COLUMN IF NOT EXISTS final_destination VARCHAR(50)`,
83	        `ALTER TABLE ${schema}"sample_event" ADD COLUMN IF NOT EXISTS notes TEXT`
84	    ];
85	    for (const stmt of statements) {
86	        try {
87	            await sequelize.query(stmt);
88	        } catch (err) {
89	            console.warn('Sample migration skipped:', err?.message);
90	        }
91	    }
92	}
93	module.exports = db;
94	
