3	const { getSignedUrl } = require('@aws-sdk/s3-request-presigner');
4	
5	// DigitalOcean Spaces (S3-compatible). Mirrors designflow-backend/helpers/digitalocean.js
6	// — only the methods sample tracking needs are ported.
7	const config = {
8	  forcePathStyle: false,
9	  endpoint: digitalocean.ENDPOINT_URL,
10	  region: 'us-west-1',
11	  credentials: {
12	    accessKeyId: digitalocean.ACCESS_KEY,
13	    secretAccessKey: digitalocean.SECRET_KEY
14	  }
15	};
16	const s3Client = new S3(config);
17	
18	// 15-minute presigned PUT URL for direct browser upload.
19	exports.getPreSignedUrl = async (fileName, contentType) => {
20	  const params = {
21	    Bucket: digitalocean.BUCKET_NAME,
22	    Key: fileName,
23	    ContentType: contentType
24	  };
25	  return await getSignedUrl(s3Client, new PutObjectCommand(params), { expiresIn: 15 * 60 });
26	};
27	
28	// Flip an uploaded object to public-read and return its CDN URL.
29	exports.setObjectPublic = async (fileName) => {
30	  await s3Client.putObjectAcl({
31	    Bucket: digitalocean.BUCKET_NAME,
32	    Key: fileName,
33	    ACL: 'public-read'
34	  });
35	  return `${digitalocean.PUBLIC_URL}/${fileName}`;
36	};
37	
38	// Delete objects by their public URL.
39	exports.deleteObjectsFromBucket = async (files) => {
40	  const Objects = (files || []).map(file => ({ Key: file.replace(digitalocean.PUBLIC_URL + '/', '') }));
41	  if (!Objects.length) return null;
42	  return await s3Client.deleteObjects({
43	    Bucket: digitalocean.BUCKET_NAME,
44	    Delete: { Objects }
45	  });
46	};
