3	// Map a model-layer error onto an HTTP response. Model methods signal failures
4	// either as a real Error or as a plain { status, message } object (e.g. a 409
5	// concurrency conflict or a 400 illegal transition).
6	function sendErr(res, err, fallback) {
7	  const httpStatus = Number(err && err.status) || 500;
8	  res.status(httpStatus).send({
9	    message: (err && err.message) || fallback || 'Unexpected error'
10	  });
11	}
