1	const sql = require('./db');
2	const Sequelize = require('sequelize');
3	const { Op } = require('sequelize');
4	const { getUserInfo } = require('../helpers/auth');
5	const status = require('../helpers/sampleStatus');
6	
7	const Sample = {};
8	const COURIERS = new Set(['ups', 'fedex', 'aae', 'bombino']);
9	
10	// Columns a client is allowed to filter the grid on (whitelist guards against
11	// AG Grid sending a colId that is not a real column).
12	const FILTERABLE = new Set([
13	  'sample_id_pk', 'origin', 'direction', 'sample_name', 'quantity',
14	  'retail_price', 'fob_cost', 'customer_id_fk', 'courier', 'tracking_number',
15	  'factory_id_fk', 'factory_group_id_fk',
16	  'box_id_fk', 'status', 'office_location', 'notes',
17	  'next_stop', 'final_destination', 'item_id_fk', 'prod_order_no_fk'
18	]);
19	
20	// Columns a client is allowed to set/update (status moves go through events).
21	const EDITABLE = [
22	  'sample_name', 'quantity', 'retail_price', 'fob_cost',
23	  'customer_id_fk', 'courier', 'tracking_number',
24	  'factory_id_fk', 'factory_group_id_fk', 'box_id_fk', 'office_location',
25	  'next_stop', 'final_destination', 'notes',
26	  'item_id_fk', 'prod_order_no_fk'
27	];
28	
29	// Translate one AG Grid filter definition into a Sequelize condition.
30	// Mirrors the buildCondition logic used in lic.model.js.
31	const buildCondition = (filterDef) => {
32	  if (!filterDef) return null;
33	
34	  if (filterDef.filterType === 'date') {
35	    const { type, dateFrom, dateTo } = filterDef;
36	    if (!dateFrom) return null;
37	    const startOfDay = new Date(dateFrom);
38	    startOfDay.setHours(0, 0, 0, 0);
39	    const endOfDay = new Date(startOfDay);
40	    endOfDay.setHours(23, 59, 59, 999);
41	    switch (type) {
42	      case 'equals': return { [Op.between]: [startOfDay, endOfDay] };
43	      case 'notEqual': return { [Op.notBetween]: [startOfDay, endOfDay] };
44	      case 'lessThan': return { [Op.lt]: startOfDay };
45	      case 'greaterThan': return { [Op.gt]: startOfDay };
46	      case 'inRange': {
47	        if (!dateTo) return null;
48	        const rangeEnd = new Date(dateTo);
49	        rangeEnd.setHours(23, 59, 59, 999);
50	        return { [Op.between]: [startOfDay, rangeEnd] };
51	      }
52	      default: return null;
53	    }
54	  }
55	
56	  if (filterDef.filterType === 'number') {
57	    const n = filterDef.filter;
58	    switch (filterDef.type) {
59	      case 'equals': return { [Op.eq]: n };
60	      case 'notEqual': return { [Op.ne]: n };
61	      case 'lessThan': return { [Op.lt]: n };
62	      case 'lessThanOrEqual': return { [Op.lte]: n };
63	      case 'greaterThan': return { [Op.gt]: n };
64	      case 'greaterThanOrEqual': return { [Op.gte]: n };
65	      case 'inRange': return { [Op.between]: [n, filterDef.filterTo] };
66	      default: return null;
67	    }
68	  }
69	
70	  // default: text
71	  const value = typeof filterDef.filter === 'string' ? filterDef.filter : '';
72	  switch (filterDef.type) {
73	    case 'contains': return { [Op.iLike]: `%${value}%` };
74	    case 'notContains': return { [Op.notILike]: `%${value}%` };
75	    case 'equals': return { [Op.eq]: filterDef.filter };
76	    case 'notEqual': return { [Op.ne]: filterDef.filter };
77	    case 'startsWith': return { [Op.iLike]: `${value}%` };
78	    case 'endsWith': return { [Op.iLike]: `%${value}` };
79	    case 'blank': return { [Op.or]: [{ [Op.eq]: null }, { [Op.eq]: '' }] };
80	    case 'notBlank': return { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] };
81	    default: return null;
82	  }
83	};
84	
85	// Server-side grid contract: ?startRow&endRow&filterModel -> { rows, totalCount }
86	Sample.list = async (req, result) => {
87	  const { startRow, endRow, filterModel } = req.query;
88	  const limit = endRow != null && startRow != null ? Number(endRow) - Number(startRow) : 100;
89	  const offset = startRow != null ? Number(startRow) : 0;
90	
91	  try {
92	    const user = await getUserInfo(req.headers.authorization);
93	    const filters = filterModel ? JSON.parse(filterModel) : {};
94	    const whereClause = {};
95	
96	    Object.entries(filters).forEach(([field, filterDef]) => {
97	      if (!FILTERABLE.has(field)) return;
98	      // Normalise AG Grid "multi" filters the same way lic.model does.
99	      let def = filterDef;
100	      if (def && def.filterType === 'multi') {
101	        def = (def.filterModels || []).find(sub => sub) || null;
102	      }
103	      const condition = buildCondition(def);
104	      if (condition) whereClause[field] = condition;
105	    });
106	
107	    if (user?.role === 'vendor') {
108	      if (user.factory_id == null || Number.isNaN(Number(user.factory_id))) {
109	        return result(null, { rows: [], totalCount: 0 });
110	      }
111	      whereClause.factory_id_fk = Number(user.factory_id);
112	    }
113	
114	    const { count, rows } = await sql.sample.findAndCountAll({
115	      where: whereClause,
116	      order: [['sample_id_pk', 'DESC']],
117	      limit,
118	      offset,
119	      distinct: true,
120	      include: sql.sample_attachment
121	        ? [{ model: sql.sample_attachment, as: 'sampleAttachments', required: false }]
122	        : []
123	    });
124	
125	    // Surface a primary_photo thumbnail URL on each row for the grid.
126	    const mapped = rows.map(r => {
127	      const plain = (r && typeof r.get === 'function') ? r.get({ plain: true }) : r;
128	      const atts = (plain && plain.sampleAttachments) || [];
129	      const primary = atts.find(a => a.primary_image) || atts[0];
130	      plain.primary_photo = primary ? primary.attachment_link : null;
131	      return plain;
132	    });
133	
134	    // Surface the box label (so the grid shows which box a sample is in).
135	    const boxIds = [...new Set(mapped.map(r => r.box_id_fk).filter(Boolean))];
136	    if (boxIds.length && sql.sample_box) {
137	      const boxes = await sql.sample_box.findAll({ where: { box_id_pk: { [Op.in]: boxIds } } });
138	      const labels = new Map(boxes.map(b => [b.box_id_pk, b.box_label]));
139	      mapped.forEach(r => {
140	        r.box_label = r.box_id_fk ? (labels.get(r.box_id_fk) || `Box #${r.box_id_fk}`) : null;
141	      });
142	    } else {
143	      mapped.forEach(r => { r.box_label = null; });
144	    }
145	
146	    return result(null, { rows: mapped, totalCount: count });
147	  } catch (err) {
148	    console.error('Sample.list error', err);
149	    return result(err);
150	  }
151	};
152	
153	Sample.getById = async (req, result) => {
154	  try {
155	    const row = await sql.sample.findByPk(Number(req.params.id), {
156	      include: [{ model: sql.sample_event, as: 'events', required: false }]
157	    });
158	    if (!row) return result({ status: 404, message: 'Sample not found' });
159	    return result(null, row);
160	  } catch (err) {
161	    console.error('Sample.getById error', err);
162	    return result(err);
