166	Sample.create = async (req, result) => {
167	  try {
168	    const user = await getUserInfo(req.headers.authorization);
169	    const body = req.body || {};
170	    const isVendor = user?.role === 'vendor';
171	    const origin = isVendor ? 'factory_offer' : (body.origin || req.sampleOrigin);
172	
173	    if (isVendor && (user.factory_id == null || Number.isNaN(Number(user.factory_id)))) {
174	      return result({ status: 403, message: 'Vendor account is not linked to a factory' });
175	    }
176	    if (isVendor && body.origin && body.origin !== 'factory_offer') {
177	      return result({ status: 403, message: 'Factory portal can only create factory offers' });
178	    }
179	
180	    if (!status.ORIGINS.includes(origin)) {
181	      return result({ status: 400, message: `origin must be one of ${status.ORIGINS.join(', ')}` });
182	    }
183	    if (body.courier && !COURIERS.has(String(body.courier).toLowerCase())) {
184	      return result({ status: 400, message: 'courier must be one of ups, fedex, aae, bombino' });
185	    }
186	    const def = status.ORIGIN_DEFAULTS[origin];
187	    const now = String(Date.now());
188	
189	    const payload = {
190	      origin,
191	      direction: def.direction,
192	      status: def.initialStatus,
193	      sample_name: body.sample_name ?? null,
194	      quantity: body.quantity ?? null,
195	      retail_price: body.retail_price ?? null,
196	      fob_cost: body.fob_cost ?? null,
197	      customer_id_fk: body.customer_id_fk ?? null,
198	      courier: body.courier ? String(body.courier).toLowerCase() : null,
199	      tracking_number: body.tracking_number ?? null,
200	      factory_id_fk: isVendor ? Number(user.factory_id) : (body.factory_id_fk ?? null),
201	      item_id_fk: body.item_id_fk ?? null,
202	      prod_order_no_fk: body.prod_order_no_fk ?? null,
203	      factory_group_id_fk: body.factory_group_id_fk ?? null,
204	      box_id_fk: body.box_id_fk ?? null,
205	      office_location: body.office_location ?? (origin === 'customer' ? 'Ningbo' : null),
206	      next_stop: body.next_stop ?? (origin === 'customer' ? 'Customer' : null),
207	      final_destination: body.final_destination ?? (origin === 'customer' ? 'Customer' : null),
