292	/**
293	 * The bidirectional check-in/out engine. The client supplies event_type +
294	 * office_location (+ optional notes, + to_status only for status_change). The
295	 * resulting backbone status is DERIVED here and written under an optimistic
296	 * guard so two concurrent moves from the same status cannot both succeed.
297	 */
298	Sample.recordEvent = async (req, result) => {
299	  try {
300	    const user = await getUserInfo(req.headers.authorization);
301	    const body = req.body || {};
302	    const sampleId = Number(body.sample_id_fk || req.params.id);
303	    const eventType = body.event_type;
304	    const office = body.office_location ?? null;
305	    const notes = body.notes ?? null;
306	    const requestedToStatus = body.to_status ?? null;
307	
308	    if (!sampleId) return result({ status: 400, message: 'sample_id_fk is required' });
309	
310	    const sample = await sql.sample.findByPk(sampleId);
311	    if (!sample) return result({ status: 404, message: 'Sample not found' });
312	
313	    const fromStatus = sample.status;
314	    const derived = status.deriveToStatus({
315	      direction: sample.direction,
316	      currentStatus: fromStatus,
317	      office,
318	      eventType,
319	      requestedToStatus
320	    });
321	    if (!derived.ok) return result({ status: derived.status, message: derived.error });
322	
323	    // Optimistic concurrency: only advance if the row is still in fromStatus.
324	    const [affected] = await sql.sample.update(
325	      {
326	        status: derived.toStatus,
327	        office_location: office ?? sample.office_location,
328	        sample_modUser: user?.name ?? null,
329	        sample_modTime: String(Date.now())
330	      },
331	      { where: { sample_id_pk: sampleId, status: fromStatus } }
332	    );
333	    if (!affected) {
334	      return result({ status: 409, message: 'Sample status changed concurrently; please retry' });
335	    }
336	
337	    const event = await sql.sample_event.create({
338	      sample_id_fk: sampleId,
339	      event_type: eventType,
340	      from_status: fromStatus,
341	      to_status: derived.toStatus,
342	      office_location: office,
343	      event_user_id_fk: user?.user_id ?? null,
344	      event_user: user?.name ?? null,
345	      event_time: new Date(),
346	      notes
347	    });
348	
349	    return result(null, {
350	      sample_id: sampleId,
351	      from_status: fromStatus,
352	      to_status: derived.toStatus,
353	      event
354	    });
355	  } catch (err) {
356	    console.error('Sample.recordEvent error', err);
357	    return result(err);
358	  }
359	};
