19	LicTracking.getAllLicenses = async (req, result) => {
20	  const { startRow, endRow, filterModel } = req.query;
21	  const limit = endRow - startRow;
22	  const offset = Number(startRow);
23	
24	  try {
25	    const filters = filterModel ? JSON.parse(filterModel) : {};
26	
27	    // 🔹 Normalize multi filters (same as ItemLibrary)
28	    Object.keys(filters).forEach(field => {
29	      if (filters[field]?.filterType === 'multi') {
30	        const validSubFilter = filters[field].filterModels.find(sub => sub);
31	        filters[field] = validSubFilter || null;
32	      }
33	    });
34	
35	    const whereClause = {};
36	
37	    if (req.query.companyCode) {
38	      whereClause.compan_code_fk = Number(req.query.companyCode);
39	    }
40	
41	    // 🔹 SAME merchGroupFilters structure
42	    const merchGroupFilters = {
43	      merchGroup01: {},
44	      merchGroup02: {},
45	      merchGroup03: {},
46	      merchGroup04: {},
47	      merchGroup05: {},
48	      merchGroup06: {},
49	      merchGroup09: {}
50	    };
51	
52	    // 🔹 SAME buildCondition (no db logic)
53	    const buildCondition = (filterDef) => {
54	      if (filterDef.filterType === 'date') {
55	        const { type, dateFrom, dateTo } = filterDef;
56	        if (!dateFrom) return null;
57	
58	        const startOfDay = new Date(dateFrom);
59	        startOfDay.setHours(0, 0, 0, 0);
60	
61	        const endOfDay = new Date(startOfDay);
62	        endOfDay.setHours(23, 59, 59, 999);
63	
64	        switch (type) {
65	          case 'equals': return { [Op.between]: [startOfDay, endOfDay] };
66	          case 'notEqual': return { [Op.notBetween]: [startOfDay, endOfDay] };
67	          case 'lessThan': return { [Op.lt]: startOfDay };
68	          case 'greaterThan': return { [Op.gt]: startOfDay };
69	          case 'inRange':
70	            if (!dateTo) return null;
71	            const rangeEnd = new Date(dateTo);
72	            rangeEnd.setHours(23, 59, 59, 999);
73	            return { [Op.between]: [startOfDay, rangeEnd] };
74	          default: return null;
75	        }
76	      }
77	
78	      
79	      if(filterDef.filterType === 'text'){
80	        const value =
81	        typeof filterDef.filter === 'string' ? filterDef.filter : '';
82	
83	      switch (filterDef.type) {
84	        case 'contains': return { [Op.iLike]: `%${value}%` };
85	        case 'notContains': return { [Op.notILike]: `%${value}%` };
86	        case 'equals': return { [Op.eq]: filterDef.filter };
87	        case 'notEqual': return { [Op.ne]: filterDef.filter };
88	        case 'startsWith': return { [Op.iLike]: `${value}%` };
89	        case 'endsWith': return { [Op.iLike]: `%${value}` };
90	        case 'blank': return { [Op.or]: [{ [Op.eq]: null }, { [Op.eq]: '' }] };
91	        case 'notBlank': return { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] };
92	        default: return null;
93	      }
94	      }
95	
96	    };
97	
98	    // 🔹 SAME filter routing logic
99	    Object.entries(filters).forEach(([field, filterDef]) => {
100	      if (!filterDef) return;
101	
102	      const dbField = mapFieldToColumn(field);
103	      const condition = buildCondition(filterDef);
104	      if (!condition) return;
105	
106	      // Route merch group filters through their joined merchGroup alias.
107	      const match = dbField.match(/^merchGroup(0[1-6]|09)/);
108	      if (match) {
109	        const key = `merchGroup${match[1]}`;
110	        merchGroupFilters[key] = condition;
111	      } else {
112	        whereClause[dbField] = condition;
113	      }
114	    });
115	
116	    // 🔹 Division codes (same pattern)
117	    const andConditions = [];
118	    const divisionCodeIds = req.query.divisionCodeIds
119	      ? JSON.parse(req.query.divisionCodeIds)
120	      : [];
121	
122	    if (divisionCodeIds.length > 0) {
123	      (divisionCodeIds.includes(1)) ? divisionCodeIds.push(2) : null;
124	      andConditions.push({
125	        [Op.or]: [
126	          { div_code_fk: { [Op.in]: divisionCodeIds } },
127	          { div_code_fk: null }
128	        ]
129	      });
130	    }
131	
132	    if (andConditions.length > 0) {
133	      whereClause[Op.and] = andConditions;
134	    }
135	
136	    // 🔹 SAME merchGroup include generator
137	    const generateMerchGroupIncludes = () =>
138	      Object.entries(merchGroupFilters).map(([key, filter]) => {
139	        const match = key.match(/^merchGroup(0[1-6]|09)/);
140	        const hasFilter = Reflect.ownKeys(filter).length > 0;
141	
142	        return {
143	          model: sql.merchGroup,
144	          as: key,
145	          required: hasFilter,
146	          where: hasFilter
147	            ? {
148	                mgTypeCode: match[1],
149	                mg_desc: filter
150	              }
151	            : undefined
152	        };
153	      });
154	
155	    const merchIncludes = generateMerchGroupIncludes();
156	
157	    // 🔹 Single query for both count and data
158	    const { count, rows } = await sql.itemHeader.findAndCountAll({
159	      where: whereClause,
160	      logging: console.log,
161	      order: [['item_id_pk', 'DESC']],
162	      limit,
163	      offset,
164	      distinct: true,
165	      include: [
166	        { model: sql.externalVendor, as: 'externalVendor' },
167	        { model: sql.itemAttachment, as: 'itemAttachments' },
168	        { model: sql.itemLicenseImage, as: 'licenseImages', required: false },
169	        { model: sql.comments, as: 'comments', required: false },
170	        {
171	          model: sql.licensingStatus,
172	          as: 'licensingStatuses',
173	          required: !!(filters?.license_status?.values?.length),
174	          where: {
175	            ...(filters?.license_status?.values?.length ? {
176	              status: { [Op.in]: filters.license_status.values }
177	            } : {}),
178	            id: { [Op.eq]: Sequelize.literal(`(
179	              SELECT MAX(id) 
180	              FROM "${process.env.SCHEMA}"."licensingStatus" AS "ls" 
181	              WHERE CAST("ls"."itemheader_id_fk" AS INTEGER) = "itemHeader"."item_id_pk"
182	            )`) }
183	          }
184	        },
185	        ...merchIncludes
186	      ]
187	    });
188	
189	    const colHeaders = await getGridHeader(['licensing_tracking']);
190	    const licensorGroups = await sql.merchGroup.findAll({
191	      where: {
192	        mgTypeCode: '05',
193	        divisionCode_id_fk: { [Op.in]: [1, 8] }
194	      }
195	    });
196	    const artistGroups = await sql.merchGroup.findAll({
197	      where: {
198	        mgTypeCode: '09'
199	      }
200	    });
201	
202	    const remappedData = await utility.remapLicItem(
203	      colHeaders,
204	      rows,
205	      licensorGroups,
206	      artistGroups
207	    );
208	
209	    result(null, {
210	      rows: remappedData,
211	      totalCount: count
212	    });
213	  } catch (err) {
214	    console.error('Error in getAllLicenses:', err);
215	    result(null, err);
216	  }
217	};
