17	async function getGridCellNotes(req) {
18	  const { gridType, rowIds } = req.body || {};
19	  assertGridType(gridType);
20	
21	  const where = { grid_type: gridType };
22	  if (Array.isArray(rowIds) && rowIds.length > 0) {
23	    where.row_id = { [Op.in]: rowIds.map((id) => String(id)) };
24	  }
25	
26	  const rows = await sql.GridCellNote.findAll({
27	    where,
28	    order: [['updated_at', 'DESC']],
29	  });
30	
31	  const notes = {};
32	  for (const row of rows) {
33	    const apiNote = toApiNote(row);
34	    if (apiNote?.text) {
35	      notes[noteKey(row.row_id, row.col_id)] = apiNote;
36	    }
37	  }
38	
39	  return { notes };
40	}
