42	async function setGridCellNote(req) {
43	  const { gridType, rowId, colId, note } = req.body || {};
44	  assertGridType(gridType);
45	
46	  if (!rowId || !colId) {
47	    const err = new Error('rowId and colId are required');
48	    err.statusCode = 400;
49	    throw err;
50	  }
51	
52	  const normalizedRowId = String(rowId);
53	  const normalizedColId = String(colId);
54	  const authorName = await resolveAuthor(req);
55	
56	  if (note === undefined || note === null) {
57	    await sql.GridCellNote.destroy({
58	      where: {
59	        grid_type: gridType,
60	        row_id: normalizedRowId,
61	        col_id: normalizedColId,
62	      },
63	    });
64	    return { success: true };
65	  }
66	
67	  const payload = fromApiNote(note, authorName);
68	  if (!payload) {
69	    await sql.GridCellNote.destroy({
70	      where: {
71	        grid_type: gridType,
72	        row_id: normalizedRowId,
73	        col_id: normalizedColId,
74	      },
75	    });
76	    return { success: true };
77	  }
78	
79	  const existing = await sql.GridCellNote.findOne({
80	    where: {
81	      grid_type: gridType,
82	      row_id: normalizedRowId,
83	      col_id: normalizedColId,
84	    },
85	  });
86	
87	  if (existing) {
88	    await existing.update({
89	      ...payload,
90	      note_author: payload.note_author || existing.note_author,
91	      created_at: existing.created_at,
92	    });
93	  } else {
94	    await sql.GridCellNote.create({
95	      grid_type: gridType,
96	      row_id: normalizedRowId,
97	      col_id: normalizedColId,
98	      ...payload,
99	      created_at: new Date(),
100	    });
101	  }
102	
103	  return { success: true };
104	}
