81	// Calculate lead time for a given product type, licensor, and number of designs
82	exports.calculateLeadTime = async (req, res) => {
83	  try {
84	    const { productSubtype, licensorName, numDesigns } = req.body;
85	
86	    if (!productSubtype || !licensorName || !numDesigns) {
87	      return res.status(400).send({
88	        message: "productSubtype, licensorName, and numDesigns are required."
89	      });
90	    }
91	
92	    // Fetch all template data for fuzzy matching
93	    const allDesignTeam = await sql.DesignTeamTime.findAll();
94	    const allLicensing = await sql.LicensingTime.findAll();
95	    const allFactory = await sql.FactoryTime.findAll();
96	
97	    // 1. Fuzzy match product type against DesignTeamTime
98	    const designMatch = fuzzyMatch(productSubtype, allDesignTeam, 'product_subtype');
99	    const designTeam = designMatch?.record || null;
100	    let designTimeDays = 0;
101	    if (designTeam && designTeam.total_hours) {
102	      designTimeDays = Math.ceil(parseFloat(designTeam.total_hours) * numDesigns / 8);
103	    }
104	
105	    // 2. Fuzzy match licensor against LicensingTime
106	    const licensingMatch = fuzzyMatch(licensorName, allLicensing, 'licensor_name');
107	    const licensing = licensingMatch?.record || null;
108	    let licensingTimeDays = 0;
109	    if (licensing) {
110	      licensingTimeDays = licensing.total_days || 0;
111	    }
112	
113	    // 3. Fuzzy match product type against FactoryTime
114	    const factoryMatch = fuzzyMatch(productSubtype, allFactory, 'product_subtype');
115	    const factory = factoryMatch?.record || null;
116	    let samplingDays = 0;
117	    let massProductionDays = 0;
118	    if (factory) {
119	      samplingDays = factory.sampling_days || 0;
120	      massProductionDays = factory.mass_production_days || 0;
121	    }
122	
123	    // 4. Total
124	    const totalLeadTime = designTimeDays + licensingTimeDays + samplingDays + massProductionDays;
125	
126	    res.send({
127	      productSubtype,
128	      licensorName,
129	      numDesigns,
130	      breakdown: {
131	        designTimeDays,
132	        licensingTimeDays,
133	        samplingDays,
134	        massProductionDays,
135	        totalLeadTime
136	      },
137	      matchInfo: {
138	        matchedProduct: designTeam?.product_subtype || 'N/A',
139	        productMatchType: designMatch?.matchType || 'none',
140	        matchedLicensor: licensing?.licensor_name || 'N/A',
141	        licensorMatchType: licensingMatch?.matchType || 'none',
142	      },
143	      details: {
144	        designTeam: designTeam || null,
145	        licensing: licensing || null,
146	        factory: factory || null
147	      }
148	    });
149	  } catch (err) {
150	    console.error('Error in calculateLeadTime:', err);
151	    res.status(500).send({ message: err.message || "Error calculating lead time." });
152	  }
153	};
